class Solution:
    def longestAwesome(self, s: str) -> int:
        n = len(s)
        prefix = [[0] * 10]
        for ch in s:
            row = prefix[-1][:]
            row[int(ch)] += 1
            prefix.append(row)
        ans = 0
        for i in range(n):
            for j in range(i + 1, n + 1):
                odd = 0
                for d in range(10):
                    if (prefix[j][d] - prefix[i][d]) % 2 == 1:
                        odd += 1
                if odd <= 1:
                    ans = max(ans, j - i)
        return ans

