class Solution:
    def longestAwesome(self, s: str) -> int:
        first = {0: -1}
        mask = 0
        ans = 0
        for i, ch in enumerate(s):
            mask ^= 1 << int(ch)
            if mask in first:
                ans = max(ans, i - first[mask])
            else:
                first[mask] = i
            for d in range(10):
                alt = mask ^ (1 << d)
                if alt in first:
                    ans = max(ans, i - first[alt])
        return ans

