var longestAwesome = function(s) {
    const first = new Map();
    first.set(0, -1);
    let mask = 0;
    let ans = 0;
    for (let i = 0; i < s.length; i++) {
        mask ^= 1 << Number(s[i]);
        if (first.has(mask)) {
            ans = Math.max(ans, i - first.get(mask));
        } else {
            first.set(mask, i);
        }
        for (let d = 0; d < 10; d++) {
            const alt = mask ^ (1 << d);
            if (first.has(alt)) {
                ans = Math.max(ans, i - first.get(alt));
            }
        }
    }
    return ans;
};
